import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class OrderController {

    @Autowired
    private OrderRepository orderRepository;

    @Autowired
    private SecurityContextHolderUtils securityContextHolderUtils;

    @PreAuthorize("hasRole('USER')")
    @GetMapping("/orders/{id}")
    public Order getOrderById(@PathVariable Long id) {
        Authentication authentication = securityContextHolderUtils.getAuthentication();
        User user = (User) authentication.getPrincipal(); // assuming User is your User entity

        return orderRepository.findByIdAndUser(id, user).orElseThrow(() -> new ResourceNotFoundException("Order not found"));
    }
}